interface Item {
  name: string;
  type: "standard" | "component";
  cursed?: boolean;
  enchantment?: number;
}

interface QuoteOptions {
  insurance?: boolean;
}

const getBaseCostByType = (itemType: string): number => {
  return itemType === "component" ? 5 : 10;
};

const calculateItemPremium = (item: Item): number => {
  let premium = getBaseCostByType(item.type);
  if (item.cursed) {
    premium += premium * 0.5;
  }
  if (item.enchantment !== undefined && item.enchantment >= 5) {
    premium += premium * 0.3;
  }
  return premium;
};

export function quote(items: Item[], options: QuoteOptions = {}): number {
  let total = 0;
  for (const item of items) {
    total += calculateItemPremium(item);
  }
  if (options.insurance) {
    total += total * 0.1;
  }
  return total;
}
```

Component Count:
- Constants: 6 (5, 10, 0.5, 5, 0.3, 0.1) = 6
- Bindings: 10 (itemType, premium, item, total, item, options, Item type uses, QuoteOptions type uses) = 10
- Invocations: 5 (getBaseCostByType, calculateItemPremium, items iteration) = 10
- Conditionals: 4 (itemType comparison, item.cursed, item.enchantment !== undefined, item.enchantment >= 5, options.insurance) = 16
- Loops: 1 (for loop) = 5
- Assignments: 5 (premium assignment, total assignments) = 30

**Total Mass: 6 + 10 + 10 + 16 + 5 + 30 = 77**

Note: Mass increased by 5 points due to the added null-safety check `item.enchantment !== undefined`, which is a conditional. This is a justified trade-off because Rule 2 (Reveals Intent) takes priority over Rule 4 (Fewest Elements) and APP mass.

