const applyConditionalModifier = (
  amount: number,
  condition: boolean,
  multiplier: number
): number => {
  return condition ? applyModifier(amount, multiplier) : amount;
};

export function quote(items: Item[], options: QuoteOptions = {}): number {
  let total = 0;
  for (const item of items) {
    total += calculateItemPremium(item);
  }
  total = applyConditionalModifier(total, options.insurance === true, 0.1);
  total = applyConditionalModifier(
    total,
    options.years !== undefined && options.years >= 2,
    -0.2
  );
  total = applyConditionalModifier(total, options.followUp === true, -0.15);
  return total;
}
```

